CREATE VIEW "transit"."stop_routes" AS (select "transit"."stop_times"."stop_id", array_agg(DISTINCT "transit"."routes"."short_name") as "route_short_names" from "transit"."stop_times" inner join "transit"."trips" on "transit"."stop_times"."trip_id" = "transit"."trips"."id" inner join "transit"."routes" on "transit"."trips"."route_id" = "transit"."routes"."id" where ("transit"."routes"."short_name" is not null) group by "transit"."stop_times"."stop_id");